insert into public.questions (
  question,
  correct_answer,
  options,
  category,
  difficulty,
  slug,
  explanation
)
values
  ('Wie sagt man "Anzeige erstatten" auf Spanisch?', 'poner una denuncia', '["poner una denuncia","presentar una solicitud","pagar una multa","firmar un contrato"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-77', '"Poner una denuncia" ist die gängige Formulierung für eine Anzeige bei der Polizei.'),
  ('Wie heißt "Streifenwagen" auf Spanisch?', 'el coche patrulla', '["el coche patrulla","el coche de carreras","el coche privado","el coche escolar"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-78', '"Coche patrulla" ist der Streifenwagen, der im Einsatz patrouilliert.'),
  ('Wie sagt man "Fahndung" auf Spanisch?', 'la búsqueda', '["la búsqueda","la basura","la burbuja","la balanza"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-79', '"Búsqueda" bedeutet Fahndung oder Suche, z. B. nach einem Verdächtigen.'),
  ('Wie heißt "Dienstnummer" auf Spanisch?', 'el número de placa', '["el número de placa","el número de sala","el número de calle","el número de serie"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-80', '"Número de placa" ist die Dienst- bzw. Badge-Nummer eines Beamten.'),
  ('Wie sagt man "Verkehrskontrolle" auf Spanisch?', 'el control de tráfico', '["el control de tráfico","el control de calidad","el control remoto","el control médico"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-81', '"Control de tráfico" bezeichnet eine polizeiliche Verkehrskontrolle.'),
  ('Wie heißt "Schutzweste" auf Spanisch?', 'el chaleco antibalas', '["el chaleco antibalas","el chaleco salvavidas","la chaqueta","la camisa"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-82', '"Chaleco antibalas" ist die Schutz- bzw. kugelsichere Weste.'),
  ('Wie sagt man "Tatwaffe" auf Spanisch?', 'el arma del crimen', '["el arma del crimen","el arma deportiva","el arma blanca","el arma legal"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-83', '"Arma del crimen" ist die Tatwaffe, also die Waffe, mit der die Tat begangen wurde.'),
  ('Wie heißt "Täter" auf Spanisch?', 'el autor', '["el autor","el actor","el auditor","el auxiliar"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-84', '"Autor" bedeutet Täter. Auch "culpable" wird für Schuldigen verwendet.'),
  ('Wie sagt man "Opfer" auf Spanisch?', 'la víctima', '["la víctima","la visita","la vista","la vitrina"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-85', '"Víctima" ist das Opfer eines Verbrechens oder Unfalls.'),
  ('Wie heißt "Beweismittel" auf Spanisch?', 'la prueba', '["la prueba","la prueba médica","la promesa","la prueba oral"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-86', '"Prueba" ist ein Beweismittel. In der Mehrzahl spricht man von "pruebas".'),
  ('Wie sagt man "Zeugenvernehmung" auf Spanisch?', 'la declaración del testigo', '["la declaración del testigo","la dirección del testigo","la detención del testigo","la defensa del testigo"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-87', '"Declaración del testigo" ist die Aussage eines Zeugen im Rahmen der Vernehmung.'),
  ('Wie heißt "Notwehr" auf Spanisch?', 'la legítima defensa', '["la legítima defensa","la defensa pública","la defensa técnica","la defensa civil"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-88', '"Legítima defensa" ist Notwehr und beschreibt eine rechtlich erlaubte Selbstverteidigung.'),
  ('Wie sagt man "Feststellung der Personalien" auf Spanisch?', 'la identificación', '["la identificación","la invitación","la información","la investigación"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-89', '"Identificación" beschreibt das Feststellen der Identität einer Person.'),
  ('Wie heißt "Fluchtfahrzeug" auf Spanisch?', 'el vehículo de fuga', '["el vehículo de fuga","el vehículo oficial","el vehículo escolar","el vehículo privado"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-90', '"Vehículo de fuga" ist das Fluchtfahrzeug, das zum Entkommen genutzt wurde.'),
  ('Wie sagt man "Falschaussage" auf Spanisch?', 'el falso testimonio', '["el falso testimonio","el testimonio real","la falsa alarma","el falso aviso"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-91', '"Falso testimonio" ist eine Falschaussage vor Polizei oder Gericht.'),
  ('Wie heißt "Durchsage über Funk" auf Spanisch?', 'el aviso por radio', '["el aviso por radio","el aviso por correo","el aviso por carta","el aviso por mano"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-92', '"Aviso por radio" ist eine Durchsage oder Meldung über Funk.'),
  ('Wie sagt man "Verdachtsmoment/Anhaltspunkt" auf Spanisch?', 'el indicio', '["el indicio","el inicio","el indicativo","el índice"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-93', '"Indicio" ist ein Hinweis oder Verdachtsmoment in Ermittlungen.'),
  ('Wie heißt "Überwachung" auf Spanisch?', 'la vigilancia', '["la vigilancia","la tolerancia","la garantía","la vacuna"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-94', '"Vigilancia" bedeutet Überwachung oder Beobachtung durch die Polizei.'),
  ('Wie sagt man "Auffinden von Spuren" auf Spanisch?', 'el hallazgo de indicios', '["el hallazgo de indicios","el hallazgo de dinero","el hallazgo de vecinos","el hallazgo de libros"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-95', '"Hallazgo de indicios" beschreibt das Auffinden und Sichern von Spuren.'),
  ('Wie heißt "polizeiliche Absperrung" auf Spanisch?', 'el cordón policial', '["el cordón policial","el cordón escolar","el cordón médico","el cordón deportivo"]'::jsonb, 'Polizei-Spanisch', 'mittel', 'polizei-spanisch-2026-96', '"Cordón policial" ist die polizeiliche Absperrung eines Bereichs.')
on conflict (lower(trim(question)), lower(trim(category)), lower(trim(difficulty))) do update
  set correct_answer = excluded.correct_answer,
      options = excluded.options,
      explanation = excluded.explanation,
      slug = excluded.slug
;

with translations as (
  select * from (values
    ('polizei-spanisch-2026-77', 'How do you say "to file a police report" in Spanish?', '["poner una denuncia","presentar una solicitud","pagar una multa","firmar un contrato"]'::jsonb, 'poner una denuncia', '"Poner una denuncia" is the common way to say filing a police report.'),
    ('polizei-spanisch-2026-78', 'How do you say "patrol car" in Spanish?', '["el coche patrulla","el coche de carreras","el coche privado","el coche escolar"]'::jsonb, 'el coche patrulla', '"Coche patrulla" is a police patrol car.'),
    ('polizei-spanisch-2026-79', 'How do you say "manhunt/search" in Spanish?', '["la búsqueda","la basura","la burbuja","la balanza"]'::jsonb, 'la búsqueda', '"Búsqueda" means a search or manhunt for a suspect.'),
    ('polizei-spanisch-2026-80', 'How do you say "badge number" in Spanish?', '["el número de placa","el número de sala","el número de calle","el número de serie"]'::jsonb, 'el número de placa', '"Número de placa" is the badge number of an officer.'),
    ('polizei-spanisch-2026-81', 'How do you say "traffic stop" in Spanish?', '["el control de tráfico","el control de calidad","el control remoto","el control médico"]'::jsonb, 'el control de tráfico', '"Control de tráfico" is a police traffic check.'),
    ('polizei-spanisch-2026-82', 'How do you say "bulletproof vest" in Spanish?', '["el chaleco antibalas","el chaleco salvavidas","la chaqueta","la camisa"]'::jsonb, 'el chaleco antibalas', '"Chaleco antibalas" means bulletproof vest.'),
    ('polizei-spanisch-2026-83', 'How do you say "murder weapon" in Spanish?', '["el arma del crimen","el arma deportiva","el arma blanca","el arma legal"]'::jsonb, 'el arma del crimen', '"Arma del crimen" is the weapon used to commit a crime.'),
    ('polizei-spanisch-2026-84', 'How do you say "perpetrator" in Spanish?', '["el autor","el actor","el auditor","el auxiliar"]'::jsonb, 'el autor', '"Autor" means the perpetrator; "culpable" refers to the guilty person.'),
    ('polizei-spanisch-2026-85', 'How do you say "victim" in Spanish?', '["la víctima","la visita","la vista","la vitrina"]'::jsonb, 'la víctima', '"Víctima" is the victim of a crime or accident.'),
    ('polizei-spanisch-2026-86', 'How do you say "evidence" in Spanish?', '["la prueba","la prueba médica","la promesa","la prueba oral"]'::jsonb, 'la prueba', '"Prueba" is evidence; plural is "pruebas".'),
    ('polizei-spanisch-2026-87', 'How do you say "witness statement" in Spanish?', '["la declaración del testigo","la dirección del testigo","la detención del testigo","la defensa del testigo"]'::jsonb, 'la declaración del testigo', '"Declaración del testigo" is a witness statement.'),
    ('polizei-spanisch-2026-88', 'How do you say "self-defense" in Spanish?', '["la legítima defensa","la defensa pública","la defensa técnica","la defensa civil"]'::jsonb, 'la legítima defensa', '"Legítima defensa" is self-defense recognized by law.'),
    ('polizei-spanisch-2026-89', 'How do you say "identity verification" in Spanish?', '["la identificación","la invitación","la información","la investigación"]'::jsonb, 'la identificación', '"Identificación" refers to verifying or establishing someone''s identity.'),
    ('polizei-spanisch-2026-90', 'How do you say "getaway vehicle" in Spanish?', '["el vehículo de fuga","el vehículo oficial","el vehículo escolar","el vehículo privado"]'::jsonb, 'el vehículo de fuga', '"Vehículo de fuga" is the vehicle used to escape.'),
    ('polizei-spanisch-2026-91', 'How do you say "false testimony" in Spanish?', '["el falso testimonio","el testimonio real","la falsa alarma","el falso aviso"]'::jsonb, 'el falso testimonio', '"Falso testimonio" means false testimony before authorities.'),
    ('polizei-spanisch-2026-92', 'How do you say "radio announcement" in Spanish?', '["el aviso por radio","el aviso por correo","el aviso por carta","el aviso por mano"]'::jsonb, 'el aviso por radio', '"Aviso por radio" is an announcement or alert over the radio.'),
    ('polizei-spanisch-2026-93', 'How do you say "clue/indication" in Spanish?', '["el indicio","el inicio","el indicativo","el índice"]'::jsonb, 'el indicio', '"Indicio" is a clue or indication in an investigation.'),
    ('polizei-spanisch-2026-94', 'How do you say "surveillance" in Spanish?', '["la vigilancia","la tolerancia","la garantía","la vacuna"]'::jsonb, 'la vigilancia', '"Vigilancia" means surveillance or monitoring.'),
    ('polizei-spanisch-2026-95', 'How do you say "finding traces" in Spanish?', '["el hallazgo de indicios","el hallazgo de dinero","el hallazgo de vecinos","el hallazgo de libros"]'::jsonb, 'el hallazgo de indicios', '"Hallazgo de indicios" refers to finding and collecting traces.'),
    ('polizei-spanisch-2026-96', 'How do you say "police cordon" in Spanish?', '["el cordón policial","el cordón escolar","el cordón médico","el cordón deportivo"]'::jsonb, 'el cordón policial', '"Cordón policial" is a police cordon that blocks off an area.')
  ) as t(slug, question, options, correct_answer, explanation)
)
insert into public.question_translations (
  question_id,
  language,
  question,
  options,
  correct_answer,
  explanation
)
select q.id, 'en', t.question, t.options, t.correct_answer, t.explanation
from translations t
join public.questions q on q.slug = t.slug
on conflict (question_id, language) do update
  set question = excluded.question,
      options = excluded.options,
      correct_answer = excluded.correct_answer,
      explanation = excluded.explanation;
